1	// Edge function: auth-signup-creator (US-019)
2	//
3	// Contract:
4	//   POST { username: string, tiktok_handle?: string, instagram_handle?: string }
5	//     → 200 { token: string, user_id: string, role: 'creator' }
6	//     → 400 { error: 'INVALID_REQUEST' | 'INVALID_JSON' }
7	//     → 422 { error: 'HANDLE_REQUIRED' }
8	//     → 409 { error: 'USERNAME_TAKEN' | 'HANDLE_TAKEN' }
9	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'JWT_ERROR' }
10	//
11	// Auth: none. This is how a creator obtains their first JWT, so the
12	// endpoint is verify_jwt=false at the gateway. The handler itself mints
13	// the token via _shared/jwt.ts (HS256, MARKETIFY_JWT_SECRET).
14	//
15	// Atomicity: the users + creator_profiles + social_links inserts run
16	// inside a single Postgres transaction via the public.auth_signup_creator
17	// RPC (us_019 migration). A failure on any insert rolls back the flow.
18	//
19	// Handle normalization: leading '@' is stripped and whitespace trimmed
20	// before the RPC call. Handles are compared case-insensitively (citext),
21	// matching social_links.handle's column type.
22	//
23	// Scope: this function only records the handles. Kicking the Apify
24	// scrapes is deferred to US-020, which will wrap this handler.
25	//
26	// Rate limit: not implemented yet. Spec §5.1 requires per-IP throttling
27	// via a signup_attempts table (does not yet exist). Same status as the
28	// sibling auth-signup-lister — tracked in progress.txt Codebase Patterns.
29	
30	import { createClient } from "npm:@supabase/supabase-js@2";
31	import { signJwt } from "../_shared/jwt.ts";
32	import { corsHeaders } from "../_shared/cors.ts";
33	
34	interface SignupRequest {
35	  username?: unknown;
36	  tiktok_handle?: unknown;
37	  instagram_handle?: unknown;
38	}
39	
40	function jsonResponse(status: number, body: unknown): Response {
41	  return new Response(JSON.stringify(body), {
42	    status,
43	    headers: { ...corsHeaders, "Content-Type": "application/json" },
44	  });
45	}
46	
47	function isString(value: unknown): value is string {
48	  return typeof value === "string";
49	}
50	
51	function normalizeHandle(value: unknown): string | null {
52	  if (!isString(value)) return null;
53	  const stripped = value.trim().replace(/^@+/, "").trim();
54	  return stripped.length > 0 ? stripped : null;
55	}
56	
57	Deno.serve(async (req) => {
58	  if (req.method === "OPTIONS") {
59	    return new Response(null, { status: 204, headers: corsHeaders });
60	  }
61	  if (req.method !== "POST") {
62	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
63	  }
64	
65	  let body: SignupRequest;
66	  try {
67	    body = await req.json();
68	  } catch {
69	    return jsonResponse(400, { error: "INVALID_JSON" });
70	  }
71	
72	  const username =
73	    isString(body.username) && body.username.trim().length > 0
74	      ? body.username.trim()
75	      : null;
76	  const tiktokHandle = normalizeHandle(body.tiktok_handle);
77	  const instagramHandle = normalizeHandle(body.instagram_handle);
78	
79	  if (!username) {
80	    return jsonResponse(400, { error: "INVALID_REQUEST" });
81	  }
82	  if (!tiktokHandle && !instagramHandle) {
83	    return jsonResponse(422, { error: "HANDLE_REQUIRED" });
84	  }
85	
86	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
87	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
88	  if (!supabaseUrl || !serviceRoleKey) {
89	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
90	  }
91	
92	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
93	    auth: { persistSession: false, autoRefreshToken: false },
94	  });
95	
96	  const { data, error } = await supabase.rpc("auth_signup_creator", {
97	    p_username: username,
98	    p_tiktok_handle: tiktokHandle,
99	    p_instagram_handle: instagramHandle,
100	  });
101	
102	  if (error) {
103	    console.error("auth_signup_creator rpc error", error);
104	    return jsonResponse(500, { error: "DB_ERROR" });
105	  }
106	
107	  const result = data as { user_id?: string; error?: string } | null;
108	  if (result?.error === "USERNAME_TAKEN") {
109	    return jsonResponse(409, { error: "USERNAME_TAKEN" });
110	  }
111	  if (result?.error === "HANDLE_TAKEN") {
112	    return jsonResponse(409, { error: "HANDLE_TAKEN" });
113	  }
114	  if (!result?.user_id) {
115	    console.error("auth_signup_creator returned unexpected shape", result);
116	    return jsonResponse(500, { error: "DB_ERROR" });
117	  }
118	
119	  const userId = result.user_id;
120	  const sessionId = crypto.randomUUID();
121	  let token: string;
122	  try {
123	    token = await signJwt({
124	      sub: userId,
125	      role: "creator",
126	      session_id: sessionId,
127	    });
128	  } catch (err) {
129	    console.error("signJwt failed", err);
130	    return jsonResponse(500, { error: "JWT_ERROR" });
131	  }
132	
133	  return jsonResponse(200, { token, user_id: userId, role: "creator" });
134	});
