1	// Edge function: apify-webhook (US-016, US-017, US-018)
2	//
3	// Contract:
4	//   POST (headers include X-Apify-Webhook-Secret)
5	//     body: {
6	//       eventType: 'ACTOR.RUN.SUCCEEDED'|'ACTOR.RUN.FAILED'
7	//                 |'ACTOR.RUN.TIMED_OUT'|'ACTOR.RUN.ABORTED',
8	//       resource: { id, defaultDatasetId, status, actId },
9	//       social_link_id, scrape_mode, run_id,
10	//       status?, apify_finished_at?, dataset_id?,   // injected via payloadTemplate
11	//     }
12	//     → 200 { ok: true, inserted?: bool, duplicate?: bool, skipped?: 'unsupported_scrape_mode' }
13	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
14	//     → 401 { error: 'UNAUTHORIZED' }
15	//     → 405 { error: 'METHOD_NOT_ALLOWED' }
16	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'APIFY_FETCH_ERROR' }
17	//
18	// Auth: no JWT — webhook-auth via constant-time compare of the
19	//   X-Apify-Webhook-Secret header against env APIFY_WEBHOOK_SECRET or
20	//   APIFY_WEBHOOK_SECRET_PREVIOUS (dual-secret rotation window per
21	//   docs/tech-architecture.md §3g). Deploy with --no-verify-jwt.
22	//
23	// Idempotency: each scrape_mode branch dispatches to its own persistence RPC
24	//   (public.apify_webhook_persist_tiktok_profile, ..._ig_details, ..._ig_posts)
25	//   that inserts one metric_snapshots row keyed on apify_run_id; the partial
26	//   unique index metric_snapshots_run_uniq makes the second webhook for the
27	//   same run a no-op. Each RPC returns {inserted, duplicate, snapshot_id?}.
28	//
29	// Scope (US-016, US-017, US-018): tiktok_profile, ig_details, and ig_posts
30	//   branches are all live. Any other scrape_mode value returns 200
31	//   { skipped: 'unsupported_scrape_mode' } so Apify does not retry.
32	//
33	// Pre-refreshing-row note (US-020 handoff): each RPC currently INSERTs (never
34	//   UPDATEs), so assumes no existing snapshot row carries this apify_run_id.
35	//   US-020 (auth-signup-creator Apify dispatch) will pre-create snapshots in
36	//   status='refreshing' before the webhook arrives — at that point the RPC
37	//   (or the denorm trigger) must be extended to UPDATE-then-denorm. See the
38	//   spec-gap note in the us_016_apify_webhook_persist_rpc migration.
39	
40	import { createClient } from "npm:@supabase/supabase-js@2";
41	import { corsHeaders } from "../_shared/cors.ts";
42	
43	const APIFY_API_BASE = "https://api.apify.com/v2";
44	
45	interface WebhookBody {
46	  eventType?: unknown;
47	  resource?: unknown;
48	  social_link_id?: unknown;
49	  scrape_mode?: unknown;
50	  run_id?: unknown;
51	  status?: unknown;
52	  apify_finished_at?: unknown;
53	  dataset_id?: unknown;
54	}
55	
56	interface ApifyResource {
57	  id: string;
58	  defaultDatasetId: string;
59	  status: string;
60	  actId: string;
61	}
62	
63	interface TikTokAuthorMeta {
64	  fans?: number;
65	  following?: number;
66	  heart?: number;
67	  video?: number;
68	  verified?: boolean;
69	}
70	
71	interface TikTokItem {
72	  authorMeta?: TikTokAuthorMeta;
73	  playCount?: number;
74	}
75	
76	interface InstagramDetailsItem {
77	  followersCount?: number;
78	  followsCount?: number;
79	  postsCount?: number;
80	  verified?: boolean;
81	}
82	
83	interface InstagramPostItem {
84	  type?: string;
85	  videoPlayCount?: number;
86	  videoViewCount?: number;
87	}
88	
89	type MetricStatus = "fresh" | "failed";
90	
91	type ScrapeMode = "tiktok_profile" | "ig_details" | "ig_posts";
92	
93	interface PersistResult {
94	  inserted?: boolean;
95	  duplicate?: boolean;
96	  snapshot_id?: string;
97	}
98	
99	const SUCCEEDED_EVENT = "ACTOR.RUN.SUCCEEDED";
100	const TERMINAL_EVENT_TYPES = new Set([
101	  SUCCEEDED_EVENT,
102	  "ACTOR.RUN.FAILED",
103	  "ACTOR.RUN.TIMED_OUT",
104	  "ACTOR.RUN.ABORTED",
105	]);
106	
107	function jsonResponse(status: number, body: unknown): Response {
108	  return new Response(JSON.stringify(body), {
109	    status,
110	    headers: { ...corsHeaders, "Content-Type": "application/json" },
111	  });
112	}
113	
114	function isNonEmptyString(value: unknown): value is string {
115	  return typeof value === "string" && value.length > 0;
116	}
117	
118	// Constant-time string compare. Lengths are compared first; when lengths
119	// differ we still iterate over the longer string to keep timing flat.
120	function timingSafeEqual(a: string, b: string): boolean {
121	  const enc = new TextEncoder();
122	  const aBytes = enc.encode(a);
123	  const bBytes = enc.encode(b);
124	  const len = Math.max(aBytes.length, bBytes.length);
125	  let diff = aBytes.length ^ bBytes.length;
126	  for (let i = 0; i < len; i++) {
127	    const ac = i < aBytes.length ? aBytes[i] : 0;
128	    const bc = i < bBytes.length ? bBytes[i] : 0;
129	    diff |= ac ^ bc;
130	  }
131	  return diff === 0;
132	}
133	
134	function verifyWebhookSecret(req: Request): boolean {
135	  const provided = req.headers.get("x-apify-webhook-secret");
136	  if (!isNonEmptyString(provided)) return false;
137	  const current = Deno.env.get("APIFY_WEBHOOK_SECRET") ?? "";
138	  const previous = Deno.env.get("APIFY_WEBHOOK_SECRET_PREVIOUS") ?? "";
139	  if (!current && !previous) return false;
140	  // Both comparisons always run (no short-circuit) so an attacker who has
141	  // recovered `current` can't time-distinguish whether `previous` is set.
142	  const matchCurrent = current ? timingSafeEqual(provided, current) : false;
143	  const matchPrevious = previous ? timingSafeEqual(provided, previous) : false;
144	  return matchCurrent || matchPrevious;
145	}
146	
147	function validResource(value: unknown): value is ApifyResource {
148	  if (!value || typeof value !== "object") return false;
149	  const r = value as Record<string, unknown>;
150	  return (
151	    isNonEmptyString(r.id) &&
152	    isNonEmptyString(r.defaultDatasetId) &&
153	    isNonEmptyString(r.status) &&
154	    isNonEmptyString(r.actId)
155	  );
156	}
157	
158	function meanPlayCount(items: TikTokItem[]): number | null {
159	  const slice = items.slice(0, 10);
160	  const views: number[] = [];
161	  for (const it of slice) {
162	    if (typeof it?.playCount === "number" && Number.isFinite(it.playCount)) {
163	      views.push(it.playCount);
164	    }
165	  }
166	  if (views.length === 0) return null;
167	  const sum = views.reduce((acc, n) => acc + n, 0);
168	  return Math.round(sum / views.length);
169	}
170	
171	// Per spec §3c: filter posts to type === "Video", pick videoPlayCount with
172	// videoViewCount as fallback, return null if zero videos so the UI can surface
173	// "Not enough video posts to compute". The Apify actor input caps results at
174	// 10, so no slice is needed here.
175	function meanInstagramVideoViews(items: InstagramPostItem[]): number | null {
176	  const views: number[] = [];
177	  for (const it of items) {
178	    if (it?.type !== "Video") continue;
179	    const candidate = typeof it.videoPlayCount === "number" &&
180	        Number.isFinite(it.videoPlayCount)
181	      ? it.videoPlayCount
182	      : (typeof it.videoViewCount === "number" &&
183	          Number.isFinite(it.videoViewCount)
184	        ? it.videoViewCount
185	        : null);
186	    if (candidate !== null) views.push(candidate);
187	  }
188	  if (views.length === 0) return null;
189	  const sum = views.reduce((acc, n) => acc + n, 0);
190	  return Math.round(sum / views.length);
191	}
192	
193	async function fetchDatasetItems(
194	  datasetId: string,
195	  apifyKey: string,
196	): Promise<unknown[]> {
197	  const url = new URL(`${APIFY_API_BASE}/datasets/${datasetId}/items`);
198	  url.searchParams.set("token", apifyKey);
199	  url.searchParams.set("clean", "1");
200	  const res = await fetch(url.toString(), { method: "GET" });
201	  if (!res.ok) {
202	    // Don't include res body — Apify can echo the token-carrying URL inside
203	    // error payloads, and this lands in edge-function logs.
204	    throw new Error(
205	      `Apify dataset '${datasetId}' fetch failed: ${res.status} ${res.statusText}`,
206	    );
207	  }
208	  const items = await res.json();
209	  if (!Array.isArray(items)) {
210	    throw new Error(`Apify dataset '${datasetId}' returned non-array payload`);
211	  }
212	  return items;
213	}
214	
215	Deno.serve(async (req) => {
216	  if (req.method === "OPTIONS") {
217	    return new Response(null, { status: 204, headers: corsHeaders });
218	  }
219	  if (req.method !== "POST") {
220	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
221	  }
222	
223	  if (!verifyWebhookSecret(req)) {
224	    return jsonResponse(401, { error: "UNAUTHORIZED" });
225	  }
226	
227	  let body: WebhookBody;
228	  try {
229	    body = await req.json();
230	  } catch {
231	    return jsonResponse(400, { error: "INVALID_JSON" });
232	  }
233	
234	  if (
235	    !isNonEmptyString(body.eventType) ||
236	    !TERMINAL_EVENT_TYPES.has(body.eventType) ||
237	    !validResource(body.resource) ||
238	    !isNonEmptyString(body.social_link_id) ||
239	    !isNonEmptyString(body.scrape_mode) ||
240	    !isNonEmptyString(body.run_id)
241	  ) {
242	    return jsonResponse(400, { error: "INVALID_REQUEST" });
243	  }
244	
245	  const scrapeMode = body.scrape_mode as ScrapeMode;
246	  if (
247	    scrapeMode !== "tiktok_profile" &&
248	    scrapeMode !== "ig_details" &&
249	    scrapeMode !== "ig_posts"
250	  ) {
251	    // Unknown scrape_mode: return 200 so Apify does not retry. The row stays
252	    // 'refreshing' until the fail-stuck-refreshing cron janitor
253	    // (docs/tech-architecture.md §15) flips it to 'failed'.
254	    return jsonResponse(200, { ok: true, skipped: "unsupported_scrape_mode" });
255	  }
256	
257	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
258	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
259	  if (!supabaseUrl || !serviceRoleKey) {
260	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
261	  }
262	
263	  const resource = body.resource as ApifyResource;
264	  const runId = body.run_id;
265	  const socialLinkId = body.social_link_id;
266	  const fetchedAt = isNonEmptyString(body.apify_finished_at)
267	    ? body.apify_finished_at
268	    : new Date().toISOString();
269	
270	  let nextStatus: MetricStatus;
271	  let items: unknown[] | null = null;
272	  let rawPayload: unknown = null;
273	  let errorMessage: string | null = null;
274	
275	  if (body.eventType === SUCCEEDED_EVENT) {
276	    const apifyKey = Deno.env.get("APIFY_KEY");
277	    if (!apifyKey) {
278	      return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
279	    }
280	    try {
281	      items = await fetchDatasetItems(resource.defaultDatasetId, apifyKey);
282	    } catch (err) {
283	      console.error("apify dataset fetch failed", {
284	        run_id: runId,
285	        dataset_id: resource.defaultDatasetId,
286	        error: err instanceof Error ? err.message : String(err),
287	      });
288	      return jsonResponse(500, { error: "APIFY_FETCH_ERROR" });
289	    }
290	    rawPayload = items;
291	    nextStatus = "fresh";
292	  } else {
293	    nextStatus = "failed";
294	    errorMessage = `apify_${body.eventType.toLowerCase().replace(/\./g, "_")}`;
295	    rawPayload = { resource, eventType: body.eventType };
296	  }
297	
298	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
299	    auth: { persistSession: false, autoRefreshToken: false },
300	  });
301	
302	  // Single source of truth for the RPC name per branch — used both as the
303	  // .rpc() call argument and in the error-log context, so the two stay in
304	  // sync if either side is renamed.
305	  const rpcName = scrapeMode === "tiktok_profile"
306	    ? "apify_webhook_persist_tiktok_profile"
307	    : scrapeMode === "ig_details"
308	    ? "apify_webhook_persist_ig_details"
